ns:xqmap.xqmapTemplate:
declare variable $CHILDSN2SCG :=map:merge((
           for $scgname in map:keys($SCG) for $snname in map:keys($SCG($scgname)('scheduler-node')) 
               for $childsnname in $SCG($scgname)('scheduler-node')($snname)('child-scheduler-nodes') return map:entry($childsnname,$scgname)), map{'duplicates':'combine'});

declare variable $FPP := 
  map:merge(for $q in /anv:device-manager/adh:device/adh:device-specific-data/bbf-frameproc:frame-processing-profiles/bbf-frameproc:frame-processing-profile 
    return map:entry(string($q/bbf-frameproc:name/text()), 
      map:merge((
        map:entry('tag',number($q/bbf-frameproc:match-criteria/bbf-frameproc:tag[bbf-frameproc:index=0]/bbf-frameproc:vlan-id/text())), 
        map:entry('push-tag', number($q/bbf-frameproc:egress-rewrite/bbf-frameproc:push-tag[bbf-frameproc:index=0]/bbf-frameproc:vlan-id/text()))))));

declare function validator-map:GetvaniByItf1($Itf_gemport) {
            let $vani_gemport:=$ITF2VANI($Itf_gemport) 
            return $vani_gemport };
       declare function validator-map:Get_joinedUniqueKey($gemportkey) {
          let $gemport:=$GEMPORT($gemportkey)
          let $vani_gemport:=validator-map:GetvaniByItf1($gemport('itf-ref'))

          let $cptype:=$VANI($vani_gemport)('channel-pair-type')
          let $cg:=$VANI($vani_gemport)('channel-group-ref')
          let $gemportid:=$gemport('gemport-id')
          let $joinedKey:=concat($cg,'=',$cptype,'=',$gemportid)
          return $joinedKey};

        declare variable $UniqueGemportidMap:=map:merge(
           let $tmpmap:=map:merge( (
               for $gemportkey in map:keys($GEMPORT)
               let $joinedKey:=validator-map:Get_joinedUniqueKey($gemportkey)
               return map:entry($joinedKey,1)) ,map{'duplicates':'combine'})
           for $tmpkey in map:keys($tmpmap)
               return map:entry($tmpkey,sum(map:get($tmpmap,$tmpkey))));

declare variable $FORWARDERS:= map:merge(for $fwd in /anv:device-manager/adh:device/adh:device-specific-data/bbf-l2-fwd:forwarding/bbf-l2-fwd:forwarders/bbf-l2-fwd:forwarder return map:entry(string($fwd/bbf-l2-fwd:name),map:merge((
            map:entry('flooding-policies',string($fwd/bbf-l2-fwd:flooding-policies)), 
            map:entry('sub-interface', for $subif in $fwd/bbf-l2-fwd:ports/bbf-l2-fwd:port/bbf-l2-fwd:sub-interface return string($subif)),
            map:entry('forwarding-database', for $fdb in $fwd/bbf-l2-fwd:mac-learning/bbf-l2-fwd:forwarding-database return string($fdb))
            ), map{'duplicates':'combine'})));

declare variable $FORWARDINGDB:= map:merge(for $fdb in /anv:device-manager/adh:device/adh:device-specific-data/bbf-l2-fwd:forwarding/bbf-l2-fwd:forwarding-databases/bbf-l2-fwd:forwarding-database return map:entry(string($fdb/bbf-l2-fwd:name),map:merge((
            map:entry('aging-timer',number($fdb/bbf-l2-fwd:aging-timer)), 
            map:entry('max-number-mac-addresses',number($fdb/bbf-l2-fwd:max-number-mac-addresses))))));

declare variable $VSI2FDB:= map:merge((
               for $fwd in map:keys($FORWARDERS) 
                   for $vsi in $FORWARDERS($fwd)('sub-interface')
                       return map:entry($vsi,$FORWARDERS($fwd)('forwarding-database'))),map{'duplicates':'combine'});

declare variable $VANI2VENET2VSI:=map:merge((
        for $vani in map:keys($VANI2VENET)
            let $vsidistinct := distinct-values(for $venet in map:get($VANI2VENET,$vani) return map:get($VENET2VSI,$venet))
                return map:entry($vani,$vsidistinct)), map{'duplicates':'combine'});

declare variable $VSI2MAXGROUPNUMBER:=map:merge(
          let $tmpmap := map:merge((for $mvpn in map:keys($MCASTVPN) for $mitf in map:keys(map:get($MCASTVPN,$mvpn)) 
              return map:entry($MCASTVPN($mvpn)($mitf)('vsi'), $MCASTVPN($mvpn)($mitf)('max-group-number'))),map{'duplicates':'combine'})
          for $tmpkey in map:keys($tmpmap) 
              return map:entry($tmpkey, sum(map:get($tmpmap,$tmpkey))));

declare variable $TDP:=map:merge(
        for $TDP in /anv:device-manager/adh:device/adh:device-specific-data/bbf-xpongemtcont:xpongemtcont/bbf-xpongemtcont:traffic-descriptor-profiles/bbf-xpongemtcont:traffic-descriptor-profile return map:entry(string($TDP/bbf-xpongemtcont:name), 
            map:merge((map:entry('fixed-bandwidth', number($TDP/bbf-xpongemtcont:fixed-bandwidth)), map:entry('maximum-bandwidth', number($TDP/bbf-xpongemtcont:maximum-bandwidth)),map:entry('assured-bandwidth',number($TDP/bbf-xpongemtcont:assured-bandwidth))))));

declare variable $TCONT2CIR:=map:merge(
           for $tcont in map:keys($TCONT) return
            map:entry($tcont, number($TDP($TCONT($tcont)('tdp'))('fixed-bandwidth'))));

declare variable $TCONT2PIR:=map:merge(
           for $tcont in map:keys($TCONT) return
            map:entry($tcont, number($TDP($TCONT($tcont)('tdp'))('maximum-bandwidth'))));

declare variable $NETVLANID := map:entry('svlanid',distinct-values(for $vsi in (let $itfs:=('vlan-sub-interface','olt-v-enet-interface','v-ani-interface')
        let $ALLOC := (for $itf in $itfs return $ALLOCMAP($itf))
        for $tmp in map:keys($VSI) where (starts-with($tmp,'SLICING_PREFIX~') or $tmp=$ALLOC) return $tmp)
            where $VSI($vsi)('interface-usage')='network-port' and map:get($VSI($vsi),'frameproc')
                return (if(map:get($VSI($vsi),'tag-0')) then ($VSI($vsi)('tag-0')) else (let $fp := $VSI($vsi)('frameproc')return $FPP($fp)('tag')))));

ns:xquery.xqueryTemplate:
declare variable $LOCALMAP external;                
        declare variable $NETVLANID:= $LOCALMAP('NETVLANID');
	    let $SVLANRANGE := for $p in tokenize(('VLAN_ID'),',') 
	        return(if(contains ($p, '-' )) then( let $c := (for $b in (let $a := tokenize($p,'-') return $a) return xs:integer($b)) return ($c[1] to $c[2])) else number($p))				
            return count(map:get($NETVLANID,'svlanid')[not(.=$SVLANRANGE)])>0

declare variable $LOCALMAP external;
		declare variable $VANI2VENET2VSI:= $LOCALMAP('VANI2VENET2VSI');
		declare variable $ITF2GEMPORT:=$LOCALMAP('ITF2GEMPORT');
		declare variable $ALLOCMAP:=$LOCALMAP('ALLOCMAP');
		some $vani in
		(let $itfs:=('vlan-sub-interface','olt-v-enet-interface','v-ani-interface')
		let $ALLOC := (for $itf in $itfs return $ALLOCMAP($itf))
		for $tmp in map:keys($VANI2VENET2VSI)
		where (starts-with($tmp,'SLICING_PREFIX~') or $tmp=$ALLOC) return $tmp)
		satisfies sum( for $vsi in map:get($VANI2VENET2VSI,$vani) return count(map:get($ITF2GEMPORT,$vsi)))>ONU_MAX_GEM

declare variable $LOCALMAP external; 
        declare variable $VANI2TCONT :=$LOCALMAP('VANI2TCONT'); 
        declare variable $ALLOCMAP:=$LOCALMAP('ALLOCMAP'); 
        some $key in 
                (let $itfs:=('vlan-sub-interface','olt-v-enet-interface','v-ani-interface')
                 let $ALLOC := (for $itf in $itfs return $ALLOCMAP($itf)) 
        for $tmp in map:keys($VANI2TCONT) 
        where (starts-with($tmp,'SLICING_PREFIX~') or $tmp=$ALLOC) return $tmp)
        satisfies count(map:get($VANI2TCONT,$key))>ONU_MAX_TCONT

declare variable $LOCALMAP external; declare variable $VANI2VENET :=$LOCALMAP('VANI2VENET');  
        declare variable $VENET2VSI:=$LOCALMAP('VENET2VSI');  declare variable $VSI:=$LOCALMAP('VSI');
        declare variable $ALLOCMAP:=$LOCALMAP('ALLOCMAP'); 
        some $vani in (
                 let $itfs:=('vlan-sub-interface','olt-v-enet-interface','v-ani-interface')
                 let $ALLOC := (for $itf in $itfs return $ALLOCMAP($itf)) 
        for $tmp in map:keys($VANI2VENET) 
        where (starts-with($tmp,'SLICING_PREFIX~') or $tmp=$ALLOC) return $tmp)
        satisfies sum(for $uni in map:get($VANI2VENET,$vani) return count(for $vsi in map:get($VENET2VSI, $uni) where $VSI($vsi)('interface-usage')='user-port' return $vsi))>ONU_MAX_VSI

declare variable $LOCALMAP external; declare variable $FORWARDERS :=$LOCALMAP('FORWARDERS');  
        declare variable $ALLOCMAP:=$LOCALMAP('ALLOCMAP'); 
        count(for $key in 
        (let $ALLOC := $ALLOCMAP('forwarder') for $tmp in map:keys($FORWARDERS)
        where (starts-with($tmp,'SLICING_PREFIX~') or $tmp=$ALLOC) return $tmp)
        where string-length($FORWARDERS($key)('flooding-policies'))>0 return $key)>MAX_NTO1_FWD

declare variable $LOCALMAP external; declare variable $FORWARDINGDB :=$LOCALMAP('FORWARDINGDB');  
        declare variable $ALLOCMAP:=$LOCALMAP('ALLOCMAP'); 
        some $key in 
        (let $ALLOC := $ALLOCMAP('forwarding-database') for $tmp in map:keys($FORWARDINGDB) 
        where (starts-with($tmp,'SLICING_PREFIX~') or $tmp=$ALLOC) return $tmp)
        satisfies $FORWARDINGDB($key)('aging-timer')>MAX_AGING_TIME

declare variable $LOCALMAP external; declare variable $VANI2VENET2VSI:= $LOCALMAP('VANI2VENET2VSI'); 
        declare variable $VSI2MAXGROUPNUMBER:=$LOCALMAP('VSI2MAXGROUPNUMBER'); 
        declare variable $ALLOCMAP:=$LOCALMAP('ALLOCMAP'); 
        some $vani in (
                 let $itfs:=('vlan-sub-interface','olt-v-enet-interface','v-ani-interface')
                 let $ALLOC := (for $itf in $itfs return $ALLOCMAP($itf)) 
        for $tmp in map:keys($VANI2VENET2VSI) 
        where (starts-with($tmp,'SLICING_PREFIX~') or $tmp=$ALLOC) return $tmp)
        satisfies sum(
                for $vsi in map:get($VANI2VENET2VSI,$vani)
                    return map:get($VSI2MAXGROUPNUMBER, $vsi))>ONU_MAX_IGMP_JOIN

declare variable $LOCALMAP external; declare variable $SCG :=$LOCALMAP('SCG'); declare variable $SN2SCG :=$LOCALMAP('SN2SCG');  
        declare variable $CHILDSN2SCG :=$LOCALMAP('CHILDSN2SCG'); 
        declare variable $ALLOCMAP :=$LOCALMAP('ALLOCMAP'); 
        some $snode in map:keys($CHILDSN2SCG)
        satisfies count(
                 let $itfs:=('vlan-sub-interface','olt-v-enet-interface','v-ani-interface')
                 let $ALLOC := (for $itf in $itfs return $ALLOCMAP($itf)) 
        for $scg in map:get($SN2SCG,$snode) where $scg=$ALLOC return $SCG($scg)('scheduler-node')($snode)('local-queue-ids'))>L2_SCHEDULER_MAX_QUEUE

declare variable $LOCALMAP external; declare variable $VANI2VENET2VSI:= $LOCALMAP('VANI2VENET2VSI'); declare variable $SCG:=$LOCALMAP('SCG');  declare variable $ALLOCMAP:=$LOCALMAP('ALLOCMAP');
        declare variable $VSI:=$LOCALMAP('VSI');
        some $vani in (
                 let $itfs:=('vlan-sub-interface','olt-v-enet-interface','v-ani-interface')
                 let $ALLOC := (for $itf in $itfs return $ALLOCMAP($itf)) 
        for $tmp in map:keys($VANI2VENET2VSI) 
        where (starts-with($tmp,'SLICING_PREFIX~') or $tmp=$ALLOC) return $tmp)
        satisfies 
        sum(let $bac-names := distinct-values(for $vsi in map:get($VANI2VENET2VSI, $vani) let $vsisnn := $VSI($vsi)('scheduler-node-name')
            for $scg in map:keys($SCG) for $scgsn in map:keys($SCG($scg)('scheduler-node'))
                where $scgsn=$vsisnn  return map:get($SCG($scg)('scheduler-node'),$scgsn)('queue-bac-names'))
             for $bac-name in $bac-names
                return /anv:device-manager/adh:device/adh:device-specific-data/bbf-qos-tm:tm-profiles/bbf-qos-tm:bac-entry
       [bbf-qos-tm:name=$bac-name]/bbf-qos-tm:max-queue-size)
        >ONU_MAX_QUEUE_SIZE

declare variable $LOCALMAP external; declare variable $VANI2TCONT:= $LOCALMAP('VANI2TCONT'); declare variable $CPART2VANI :=$LOCALMAP('CPART2VANI');    declare variable $TCONT :=$LOCALMAP('TCONT');    declare variable $TDP :=$LOCALMAP('TDP');   declare variable $ALLOCMAP :=$LOCALMAP('ALLOCMAP');   declare variable $TCONT2CIR :=$LOCALMAP('TCONT2CIR');   
                 let $itfs:=('vlan-sub-interface','olt-v-enet-interface','v-ani-interface')
                 let $ALLOC := (for $itf in $itfs return $ALLOCMAP($itf)) 
      let $tconts:=(for $vani in map:get($CPART2VANI,'CHANNEL_PARTITION_NAME') 
        where (starts-with($vani,'SLICING_PREFIX~') or $vani=$ALLOC) 
      return $VANI2TCONT($vani))
      return sum(for $tcont in $tconts  return map:get($TCONT2CIR, $tcont))>PON_US_MAX_CIR

declare variable $LOCALMAP external; declare variable $VANI2TCONT:= $LOCALMAP('VANI2TCONT'); declare variable $CPART2VANI :=$LOCALMAP('CPART2VANI');    declare variable $TCONT :=$LOCALMAP('TCONT');    declare variable $TDP :=$LOCALMAP('TDP');   declare variable $ALLOCMAP :=$LOCALMAP('ALLOCMAP');   declare variable $TCONT2PIR :=$LOCALMAP('TCONT2PIR');   
                 let $itfs:=('vlan-sub-interface','olt-v-enet-interface','v-ani-interface')
                 let $ALLOC := (for $itf in $itfs return $ALLOCMAP($itf)) 
      let $tconts:=(for $vani in map:get($CPART2VANI,'CHANNEL_PARTITION_NAME') 
        where (starts-with($vani,'SLICING_PREFIX~') or $vani=$ALLOC) 
      return $VANI2TCONT($vani))
      return sum(for $tcont in $tconts  return map:get($TCONT2PIR, $tcont))>PON_US_MAX_PIR

declare variable $LOCALMAP external; declare variable $VANI2TCONT:= $LOCALMAP('VANI2TCONT'); declare variable $CPART2VANI :=$LOCALMAP('CPART2VANI');    declare variable $TCONTM :=$LOCALMAP('TCONT');    declare variable $ALLOCMAP :=$LOCALMAP('ALLOCMAP');    
                 let $itfs:=('vlan-sub-interface','olt-v-enet-interface','v-ani-interface')
                 let $ALLOC := (for $itf in $itfs return $ALLOCMAP($itf)) 
        let $tconts:=(for $vani in map:get($CPART2VANI,'CHANNEL_PARTITION_NAME') 
        where (starts-with($vani,'SLICING_PREFIX~') or $vani=$ALLOC) 
        return $VANI2TCONT($vani))
        let $result:=(for $tcont in $tconts return $TCONTM($tcont)('jitter-tolerance')<PON_JT_TCONT)
        return $result=true()

declare variable $LOCALMAP external; 
        declare variable $VANI2TCONT:= $LOCALMAP('VANI2TCONT'); 
        declare variable $CPART2VANI :=$LOCALMAP('CPART2VANI');    
        declare variable $ALLOCMAP :=$LOCALMAP('ALLOCMAP');    
        some $vani in (
                 let $itfs:=('vlan-sub-interface','olt-v-enet-interface','v-ani-interface')
                 let $ALLOC := (for $itf in $itfs return $ALLOCMAP($itf)) 
            for $tmp in map:get($CPART2VANI,'CHANNEL_PARTITION_NAME')
                where (starts-with($tmp,'SLICING_PREFIX~') or $tmp=$ALLOC) return $tmp)
            satisfies count($VANI2TCONT($vani))>PON_ONU_MAX_TCONT
